// Conformal LEC RTL vs RTL: combinational equivalence (no netlist, no technology library).
// Golden and revised in ./rtl/golden.v, ./rtl/revised.v.
// Uses -SystemVerilog for SV support (logic, always_comb, int, $bits, etc); backward compatible with Verilog.

set undefined cell black_box
read design ./rtl/golden.v -SystemVerilog -Golden
read design ./rtl/revised.v -SystemVerilog -Revised

// Switch to LEC mode and compare
set system mode lec
add compared points -all
compare
exit -force

files.rtlpp_01369.v:
module rtlpp_01369 (
  address,
  chipselect,
  clk,
  reset_n,
  write_n,
  writedata,
  out_port,
  readdata
);

  output             out_port;
  output  [ 31: 0]   readdata;
  input   [  1: 0]   address;
  input              chipselect;
  input              clk;
  input              reset_n;
  input              write_n;
  input   [ 31: 0]   writedata;

  reg                data_out;
  wire               read_mux_out;

  assign read_mux_out = (address == 0) & data_out;

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
      data_out <= 0;
    else if (chipselect && ~write_n && (address == 0))
      data_out <= writedata[0];
  end

  assign readdata = {31'b0, read_mux_out};
  assign out_port = data_out;

endmodule

