  4'b1111: if(BaudTick) state <= 4'b0010; 
  4'b0010: if(BaudTick) state <= 4'b0011; 
  4'b0011: if(BaudTick) state <= 4'b0000; 
  default: if(BaudTick) state <= 4'b0000; 
  endcase 
  reg muxbit; 
  always @( * ) 
  case(state[2:0]) 
