  count_clk1 <= 31'b0; 
  end 
  count_clk0 <= count_clk0 + 1'b1; 
  end 
  high: begin 
  if (count_clk0) begin 
  pw_low <= count_clk0; 
  count_clk0 <= 31'b0; 
  end 
  count_clk1 <= count_clk1 + 1'b1; 
  end 
  default: begin 
  pw_low <= 31'bX; 
  pw_high <= 31'bX; 
  count_clk0 <= 31'b0; 
  count_clk1 <= 31'b0; 
  end 
  endcase 
  end 
  pwm_prev <= pwm; 
  end 
  always @ (posedge clk) begin 
  if (reset) ps <= init; 
  else ps <= ns; 
