        .a(xor_a),
        .b(xor_b),
        .out(xor_out)
    );

    functional_module func_mod (
        .mux_out(mux_out),
        .xor_out(xor_out),
        .result(func_out)
    );

    control_logic ctrl_logic (
        .mux_result(func_out),
        .xor_result(xor_out),
        .select(control_select),
        .final_out(system_out)
    );
endmodule

