module autovcoder_019940 (  // Clock in ports
                          // Clock out ports
    output cpu_clk,
    output timer_clk,
    input  clk_in1
);
  // Input buffering
  //------------------------------------
  wire clk_in1_clk_pll;
  wire clk_in2_clk_pll;
  IBUF clkin1_ibufg (
      .O(clk_in1_clk_pll),
      .I(clk_in1)
  );




  // Clocking PRIMITIVE
  //------------------------------------

  // Instantiation of the MMCM PRIMITIVE
  //    * Unused inputs are tied off
  //    * Unused outputs are labeled unused

  wire        cpu_clk_clk_pll;
  wire        timer_clk_clk_pll;
  wire        clk_out3_clk_pll;
  wire        clk_out4_clk_pll;
  wire        clk_out5_clk_pll;
  wire        clk_out6_clk_pll;
  wire        clk_out7_clk_pll;

  wire [15:0] do_unused;
  wire        drdy_unused;
  wire        psdone_unused;
  wire        locked_int;
  wire        clkfbout_clk_pll;
  wire        clkfbout_buf_clk_pll;
  wire        clkfboutb_unused;
  wire        clkout2_unused;
  wire        clkout3_unused;
  wire        clkout4_unused;
  wire        clkout5_unused;
  wire        clkout6_unused;
  wire        clkfbstopped_unused;
  wire        clkinstopped_unused;

  PLLE2_ADV #(
      .BANDWIDTH         ("OPTIMIZED"),
      .COMPENSATION      ("ZHOLD"),
      .STARTUP_WAIT      ("FALSE"),
      .DIVCLK_DIVIDE     (1),
      .CLKFBOUT_MULT     (9),
      .CLKFBOUT_PHASE    (0.000),
      .CLKOUT0_DIVIDE    (18),
      .CLKOUT0_PHASE     (0.000),
      .CLKOUT0_DUTY_CYCLE(0.500),
      .CLKOUT1_DIVIDE    (9),
      .CLKOUT1_PHASE     (0.000),
      .CLKOUT1_DUTY_CYCLE(0.500),
      .CLKIN1_PERIOD     (10.000)
  ) plle2_adv_inst
  // Output clocks
  (
      .CLKFBOUT(clkfbout_clk_pll),
      .CLKOUT0 (cpu_clk_clk_pll),
      .CLKOUT1 (timer_clk_clk_pll),
      .CLKOUT2 (clkout2_unused),
      .CLKOUT3 (clkout3_unused),
      .CLKOUT4 (clkout4_unused),
      .CLKOUT5 (clkout5_unused),
      // Input clock control
      .CLKFBIN (clkfbout_buf_clk_pll),
      .CLKIN1  (clk_in1_clk_pll),
      .CLKIN2  (1'b0),
      // Tied to always select the primary input clock
      .CLKINSEL(1'b1),
      // Ports for dynamic reconfiguration
      .DADDR   (7'h0),
      .DCLK    (1'b0),
      .DEN     (1'b0),
      .DI      (16'h0),
      .DO      (do_unused),
      .DRDY    (drdy_unused),
      .DWE     (1'b0),
      // Other control and status signals
      .LOCKED  (locked_int),
      .PWRDWN  (1'b0),
      .RST     (1'b0)
  );

  // Clock Monitor clock assigning
  //--------------------------------------
  // Output buffering
  //-----------------------------------

  BUFG clkf_buf (
      .O(clkfbout_buf_clk_pll),
      .I(clkfbout_clk_pll)
  );






  BUFG clkout1_buf (
      .O(cpu_clk),
      .I(cpu_clk_clk_pll)
  );


  BUFG clkout2_buf (
      .O(timer_clk),
      .I(timer_clk_clk_pll)
  );



endmodule

