					end
					else if (debounce_count[N_dc-2]) begin
						if (MCEN_count == 4'b1000) begin
							state <= MCEN_cont;
						end
						else begin
							state <= MCEN_st;
						end
					end
			   	end
				MCEN_cont: begin 
					if (!PB) begin
						state <= CCR;
					end
			   	end
			   	CCR: begin
					debounce_count <= 0;
					MCEN_count <= 0;
					state <= WFCR;
			   	end
				WFCR: begin
					debounce_count <= debounce_count + 1;
					if (PB) begin
						state <= WH;
					end
					else if (debounce_count[N_dc-2]) begin
						state <= INI;
					end
			   	end
			endcase		    
	   	end
	end 
endmodule

