module rtlpp_06036 (
    address,
    chipselect,
    clk,
    reset_n,
    write_n,
    writedata,

    irq,
    readdata,
    resetrequest
);

  output           irq;
  output  [15:0]   readdata;
  output           resetrequest;
  input   [2:0]    address;
  input            chipselect;
  input            clk;
  input            reset_n;
  input            write_n;
  input   [15:0]   writedata;

  wire             clk_en;
  wire             control_interrupt_enable;
  reg              control_register;
  wire             control_wr_strobe;
  reg              counter_is_running;
  wire             counter_is_zero;
  wire    [23:0]   counter_load_value;
  reg              delayed_counter_is_zero;
  wire             do_start_counter;
  wire             do_stop_counter;
  reg              force_reload;
  reg     [23:0]   internal_counter;
  wire             irq;
  wire             period_h_wr_strobe;
  wire             period_l_wr_strobe;
  wire    [15:0]   read_mux_out;
  reg     [15:0]   readdata;
  wire             resetrequest;
  wire             start_strobe;
  wire             status_wr_strobe;
  wire             timeout_event;
  reg              timeout_occurred;

  assign clk_en = 1;

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
      internal_counter <= 24'h98967F;
    else if (counter_is_running || force_reload) begin
      if (counter_is_zero || force_reload)
        internal_counter <= counter_load_value;
      else
        internal_counter <= internal_counter - 1;
    end
  end

  assign counter_is_zero = (internal_counter == 0);
  assign counter_load_value = 9999999;

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
      force_reload <= 0;
    else if (clk_en)
      force_reload <= period_h_wr_strobe || period_l_wr_strobe;
  end

  assign do_start_counter = start_strobe;
  assign do_stop_counter = 0;

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
      counter_is_running <= 1'b0;
    else if (clk_en) begin
      if (do_start_counter)
        counter_is_running <= 1'b1;
      else if (do_stop_counter)
        counter_is_running <= 1'b0;
    end
  end

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
      delayed_counter_is_zero <= 0;
    else if (clk_en)
      delayed_counter_is_zero <= counter_is_zero;
  end

  assign timeout_event = (counter_is_zero & ~delayed_counter_is_zero);

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
      timeout_occurred <= 0;
    else if (clk_en) begin
      if (status_wr_strobe)
        timeout_occurred <= 0;
      else if (timeout_event)
        timeout_occurred <= 1;
    end
  end

  assign irq = timeout_occurred && control_interrupt_enable;
  assign resetrequest = timeout_occurred;

  assign read_mux_out = ({16{address == 1}} & {15'b0, control_register}) |
                        ({16{address == 0}} & {14'b0, counter_is_running, timeout_occurred});

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
      readdata <= 0;
    else if (clk_en)
      readdata <= read_mux_out;
  end

  assign period_l_wr_strobe = chipselect && ~write_n && (address == 2);
  assign period_h_wr_strobe = chipselect && ~write_n && (address == 3);
  assign control_wr_strobe = chipselect && ~write_n && (address == 1);

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
      control_register <= 0;
    else if (control_wr_strobe)
      control_register <= writedata[0];
  end

  assign start_strobe = writedata[2] && control_wr_strobe;
  assign control_interrupt_enable = control_register;
  assign status_wr_strobe = chipselect && ~write_n && (address == 0);

endmodule

