    genvar g;
    wire [LIST_CAP-1:0] search_result;
    generate
        for (g = 0; g < LIST_CAP; g = g+1) begin: SEARCH
            assign search_result[g] = store_flag & (((list[g][2*ADDR_WIDTH-1:ADDR_WIDTH] == search_addr) &&
                                    (ways[g][2*WAY_WIDTH-1:WAY_WIDTH] == search_way)) ||
