                                    (ways[g][2*WAY_WIDTH-1:0] == search_way)));
        end
    endgenerate

    assign req_error = | {
        add_error,
        store_error,
        ~((add_flag ^ fetch_flag) ^ (add_flag ^ store_flag) ^ (fetch_flag ^ store_flag))
    };

endmodule

