    input          CLK,
    input          CE,
    input          SEL,
    input          MODE,
    input          BC,
    input          BDIR,
    input   [7:0]  DI,
    output  [7:0]  CHANNEL_A,
    output  [7:0]  CHANNEL_B,
    output  [7:0]  CHANNEL_C
);

