always @(posedge CLK or posedge RESET) begin
    if (RESET) begin
        reg_a <= 8'b0;
        reg_b <= 8'b0;
        reg_c <= 8'b0;
    end else if (CE) begin
        if (BDIR) begin
            if (SEL) begin
                if (BC) begin
                    reg_a <= DI;
                end else begin
                    reg_b <= DI;
                end
            end else begin
                reg_c <= DI;
            end
        end
    end
end

assign CHANNEL_A = reg_a;
