    output reg [7:0] x,
    output reg [7:0] y,
    output reg [7:0] act1,
    output reg [7:0] act2,
    output reg [1:0] i
);

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
      c1 <= 8'd0;
      x <= 8'd0;
      y <= 8'd0;
      act1 <= 8'd0;
      act2 <= 8'd0;
      i <= 2'd0;
    end else begin
      case (i)


        0: begin

          if (x == c1) begin
            x <= x + 8'd10;
            act1 <= act1 + 1'b1;
            // act1 = act1 + 1'b1;
          end

          if (y == c1) begin
            y <= y + 1'b1;
