          end

          if (c1 == 100 - 1) begin
            c1 <= 8'd0;
            x  <= 8'd0;
            y  <= 8'd0;
            i  <= i + 1'b1;
          end else c1 <= c1 + 1'b1;

        end

        1: begin
          act1 <= 8'd0;
          act2 <= 8'd0;
          i <= 0;
        end

      endcase
    end
  end


