                offsetX <= pixelX % OBJECT_WIDTH_X;
                offsetY <= pixelY;
                case (current_number)
                    2'b00: current_digit <= digit1;
                    2'b01: current_digit <= 4'hA;
                    2'b10: current_digit <= digit2;
                    2'b11: current_digit <= digit3;
                endcase
            end
            else begin
                drawingRequest <= 1'b0;
                offsetX <= 11'b0;
                offsetY <= 11'b0;
            end
        end
    end

endmodule

