module origen_113568 (
    input wire clk,
    input wire reset,
    input wire [31:0] data_save,
    input wire [2:0] count_out,
    input wire count_enable,
    output reg [127:0][15:0] curr_count,
    output reg finish_cnt
);

    reg [7:0] data1, data2, data3, data4;
    reg [7:0] data_pro;
    reg [127:0] sig_detect;
    integer i;

    always @(*) begin
        data1 = data_save[7:0];
        data2 = data_save[15:8];
        data3 = data_save[23:16];
        data4 = data_save[31:24];

        case (count_out)
            3'd0: data_pro = data1;
            3'd1: data_pro = data2;
            3'd2: data_pro = data3;
            3'd3: data_pro = data4;
            default: data_pro = 8'd0;
        endcase
    end

    always @(posedge clk or negedge reset) begin
        if (!reset) begin
            sig_detect <= 128'd0;
        end else if (count_enable) begin
            sig_detect[data_pro] <= 1'b1;
        end
    end

    always @(posedge clk or negedge reset) begin
        if (!reset) begin
            for (i = 0; i < 128; i = i + 1) begin
                curr_count[i] <= 16'd0;
            end
            finish_cnt <= 1'b0;
        end else begin
            for (i = 0; i < 128; i = i + 1) begin
                if (sig_detect[i]) begin
                    curr_count[i] <= curr_count[i] + 1'b1;
                end
            end
            finish_cnt <= (count_out == 3'd4);
        end
    end

endmodule

