      add01 <= stored1 + stored0;
      add23 <= stored3 + stored2;
      add4 <= stored4;

      mul_out_1 <= add01 + add23;
      mul_out_2 <= add4;

      mul_out <= mul_out_1 + mul_out_2;
    end
  end
