    end else if (cnt_flag) begin
        if (data == DATA_MAX) begin
            data <= 20'd0;
        end else begin
            data <= data + 1'b1;
        end
    end
end

// Segment enable
always @(posedge sys_clk or negedge sys_rst_n) begin
