module origen_057342(
    input clk,
    output reg segment1, segment2, segment3, segment4,
    output reg [6:0] segmentShow,
    output dp
);

reg [26:0] clkRefresh = 0;
reg [1:0] segmentID = 0;
reg [3:0] digit = 3;
reg [3:0] ten = 8;
reg [3:0] hundred = 3;
reg [3:0] thousand = 10;
reg [3:0] value;
reg [6:0] abcdefg;
reg s1 = 1, s2 = 1, s3 = 1, s4 = 1;

always @(posedge clk) begin
    clkRefresh <= clkRefresh + 1;
    if (clkRefresh == 27'd208333) begin
        clkRefresh <= 0;
        segmentID <= segmentID + 1;

        case(segmentID)
            2'b00: begin s1 <= 0; s2 <= 1; s3 <= 1; s4 <= 1; value <= digit; end
            2'b01: begin s1 <= 1; s2 <= 0; s3 <= 1; s4 <= 1; value <= ten; end
            2'b10: begin s1 <= 1; s2 <= 1; s3 <= 0; s4 <= 1; value <= hundred; end
            2'b11: begin s1 <= 1; s2 <= 1; s3 <= 1; s4 <= 0; value <= thousand; end
        endcase

        case(value)
            4'd0: abcdefg <= 7'b1111110;
            4'd1: abcdefg <= 7'b0110000;
            4'd2: abcdefg <= 7'b1101101;
            4'd3: abcdefg <= 7'b1111001;
            4'd4: abcdefg <= 7'b0110011;
            4'd5: abcdefg <= 7'b1011011;
            4'd6: abcdefg <= 7'b1011111;
            4'd7: abcdefg <= 7'b1110000;
            4'd8: abcdefg <= 7'b1111111;
            4'd9: abcdefg <= 7'b1111011;
            default: abcdefg <= 7'b0000000;
        endcase
    end
end

always @(*) begin
    segment1 = s1;
    segment2 = s2;
    segment3 = s3;
    segment4 = s4;
    segmentShow = abcdefg;
end

assign dp = 1'b1;

endmodule

