module origen_106047 (
    input wire clk,
    input wire rst_n,

    // CPU Interface
    input wire [31:0] cpu_if_address,
    input wire [31:0] cpu_if_write_data,
    input wire cpu_if_read,
    input wire cpu_if_write,
    output reg [31:0] cpu_if_read_data,
    output reg cpu_if_access_complete,

    // SPI Controller Interface
    output reg [7:0] command,
    output reg read_not_write,
    output reg [31:0] address,
    output reg [1:0] address_bytes,
    output reg address_valid,
    output reg [2:0] dummy_cycles,
    output reg dummy_valid,
    output reg [7:0] data_bytes,
    output reg data_valid,
    output reg access_request,
    input wire access_complete
);

    // Register declarations
    reg [31:0] reg_0, reg_1, reg_2, reg_3, reg_4;
    reg transaction_in_progress;

    // Write operation
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            reg_0 <= 32'h0;
            reg_1 <= 32'h0;
            reg_2 <= 32'h0;
            reg_3 <= 32'h0;
            reg_4 <= 32'h0;
            access_request <= 1'b0;
            transaction_in_progress <= 1'b0;
        end else begin
            if (cpu_if_write) begin
                case (cpu_if_address[4:2])
                    3'b000: begin
                        reg_0 <= cpu_if_write_data;
                        access_request <= 1'b1;
                    end
                    3'b001: reg_1 <= cpu_if_write_data;
                    3'b010: reg_2 <= cpu_if_write_data;
                    3'b011: reg_3 <= cpu_if_write_data;
                    3'b100: reg_4 <= cpu_if_write_data;
                endcase
            end else begin
                access_request <= 1'b0;
            end

            if (access_request)
                transaction_in_progress <= 1'b1;
            else if (access_complete)
                transaction_in_progress <= 1'b0;
        end
    end

    // Read operation
    always @(posedge clk) begin
        if (cpu_if_read) begin
            case (cpu_if_address[4:2])
                3'b000: cpu_if_read_data <= reg_0;
                3'b001: cpu_if_read_data <= reg_1;
                3'b010: cpu_if_read_data <= reg_2;
                3'b011: cpu_if_read_data <= reg_3;
                3'b100: cpu_if_read_data <= reg_4;
                default: cpu_if_read_data <= 32'h0;
            endcase
        end
    end

    // CPU interface access complete
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            cpu_if_access_complete <= 1'b0;
        else
            cpu_if_access_complete <= cpu_if_read | cpu_if_write;
    end

    // SPI Controller Interface signals
    always @(*) begin
        command = reg_0[7:0];
        read_not_write = reg_0[8];
        address = reg_1;
        address_bytes = reg_2[1:0];
        address_valid = reg_2[2];
        dummy_cycles = reg_3[2:0];
        dummy_valid = reg_3[3];
        data_bytes = reg_4[7:0];
        data_valid = reg_4[8];
    end

endmodule

files.origen_061407.v:
module origen_061407(
    input wire clk,
    input wire clk_en,
    input wire reset,
    input wire start,
    input wire [31:0] dataa,
    input wire [31:0] datab,
    output reg [31:0] result,
    output reg done
);

    // FSM states
    localparam IDLE = 2'd0, CALCULANDO = 2'd1, PRONTO = 2'd2;
    reg [1:0] state, next_state;

    // Sub-FSM states
    localparam SUB = 2'd0, CHECK = 2'd1, ADD = 2'd2, SHIFT = 2'd3;
    reg [1:0] sub_state;

    // Internal registers
    reg [31:0] quociente, divisor;
    reg [32:0] resto;
    reg [5:0] count;

    // FSM state transition
    always @(posedge clk or posedge reset) begin
        if (reset)
            state <= IDLE;
        else if (clk_en)
            state <= next_state;
    end

    // Next state logic
    always @(*) begin
        case (state)
            IDLE: next_state = start ? CALCULANDO : IDLE;
            CALCULANDO: next_state = (count == 6'd33) ? PRONTO : CALCULANDO;
            PRONTO: next_state = IDLE;
            default: next_state = IDLE;
        endcase
    end

    // Main operation logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            quociente <= 32'd0;
            divisor <= 32'd0;
            resto <= 33'd0;
            count <= 6'd0;
            result <= 32'd0;
            done <= 1'b0;
            sub_state <= SUB;
        end else if (clk_en) begin
            case (state)
                IDLE: begin
                    if (start) begin
                        quociente <= 32'd0;
                        divisor <= datab;
                        resto <= {1'b0, dataa};
                        count <= 6'd0;
                        done <= 1'b0;
                    end
                end
                CALCULANDO: begin
                    case (sub_state)
                        SUB: begin
                            resto <= resto - {1'b0, divisor};
                            sub_state <= CHECK;
                        end
                        CHECK: begin
                            if (resto[32]) begin
                                sub_state <= ADD;
                            end else begin
                                quociente <= {quociente[30:0], 1'b1};
                                sub_state <= SHIFT;
                            end
                        end
                        ADD: begin
                            resto <= resto + {1'b0, divisor};
                            quociente <= {quociente[30:0], 1'b0};
                            sub_state <= SHIFT;
                        end
                        SHIFT: begin
                            divisor <= {1'b0, divisor[31:1]};
                            count <= count + 1;
                            sub_state <= SUB;
                        end
                    endcase
                end
                PRONTO: begin
                    result <= quociente;
                    done <= 1'b1;
                end
            endcase
        end
    end

endmodule

