module autovcoder_030129 (
    clk,
    ena,
    z,
    d,
    q,
    s,
    div0,
    ovf
);

  //
  // parameters
  //
  parameter z_width = 16;
  parameter d_width = z_width / 2;

  //
  // inputs & outputs
  //
  input clk;  // system clock
  input ena;  // clock enable

  input [z_width -1:0] z;  // divident
  input [d_width -1:0] d;  // divisor
  output [d_width -1:0] q;  // quotient
  reg [d_width-1:0] q;
  output [d_width -1:0] s;  // remainder
  reg [d_width-1:0] s;
  output div0;
  reg div0;
  output ovf;
  reg ovf;

  //
  // functions
  //
  function [z_width:0] gen_s;
    input [z_width:0] si;
    input [z_width:0] di;
    begin
      if (si[z_width]) gen_s = {si[z_width-1:0], 1'b0} + di;
      else gen_s = {si[z_width-1:0], 1'b0} - di;
    end
  endfunction

  function [d_width-1:0] gen_q;
    input [d_width-1:0] qi;
    input [z_width:0] si;
    begin
      gen_q = {qi[d_width-2:0], ~si[z_width]};
    end
  endfunction

  function [d_width-1:0] assign_s;
    input [z_width:0] si;
    input [z_width:0] di;
    reg [z_width:0] tmp;
    begin
      if (si[z_width]) tmp = si + di;
      else tmp = si;

      assign_s = tmp[z_width-1:z_width-4];
    end
  endfunction

  //
  // variables
  //
  reg [d_width-1:0] q_pipe[d_width-1:0];
  reg [  z_width:0] s_pipe[  d_width:0];
  reg [  z_width:0] d_pipe[  d_width:0];

  reg [d_width:0] div0_pipe, ovf_pipe;
  //
  // perform parameter checks
  //
`ifdef SIMULATION
  initial begin
    if (d_width !== z_width / 2) $display("div.v parameter error (d_width != z_width/2).");
  end
`endif

  integer n0, n1, n2, n3;

  // generate divisor (d) pipe
  always @(d) d_pipe[0] <= {1'b0, d, {(z_width - d_width) {1'b0}}};

  always @(posedge clk)
    if (ena)
      for (n0 = 1; n0 <= d_width; n0 = n0 + 1) d_pipe[n0] <= #1 d_pipe[n0-1];

  // generate internal remainder pipe
  always @(z) s_pipe[0] <= z;

  always @(posedge clk)
    if (ena)
      for (n1 = 1; n1 <= d_width; n1 = n1 + 1) s_pipe[n1] <= #1 gen_s(s_pipe[n1-1], d_pipe[n1-1]);

  // generate quotient pipe
  always @(posedge clk) q_pipe[0] <= #1 0;

  always @(posedge clk)
    if (ena)
      for (n2 = 1; n2 < d_width; n2 = n2 + 1) q_pipe[n2] <= #1 gen_q(q_pipe[n2-1], s_pipe[n2]);


  // flags (divide_by_zero, overflow)
  always @(z or d) begin
    ovf_pipe[0]  <= !(z[z_width-1:d_width] < d);
    div0_pipe[0] <= ~|d;
  end

  always @(posedge clk)
    if (ena)
      for (n3 = 1; n3 <= d_width; n3 = n3 + 1) begin
        ovf_pipe[n3]  <= #1 ovf_pipe[n3-1];
        div0_pipe[n3] <= #1 div0_pipe[n3-1];
      end

  // assign outputs
  always @(posedge clk) if (ena) ovf <= #1 ovf_pipe[d_width];

  always @(posedge clk) if (ena) div0 <= #1 div0_pipe[d_width];

  always @(posedge clk) if (ena) q <= #1 gen_q(q_pipe[d_width-1], s_pipe[d_width]);

  always @(posedge clk) if (ena) s <= #1 assign_s(s_pipe[d_width], d_pipe[d_width]);
endmodule

